#include<cstdio>
#include<vector>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2022;std::vector<int> G[N],T[N];int n,m,a[N],Deg[N],deg[N],stk[N],ans[N];
int main()
{
	n=read();m=read();rep(1,n,i)a[i]=n-read()+1;
	rep(1,m,i){int y=read(),x=read();++Deg[y];G[x].push_back(y);}
	rep(1,n,i)
	{
		memcpy(deg,Deg,(n+3)<<2);int cdt=0,Ans=-1,top=0;
		int t=1;rep(1,n,i)if(!deg[i]){if(a[i]==1)stk[++top]=i;else T[a[i]].push_back(i);}
		while(top)
		{
			int u=stk[top--];if(u==i&&top){int tmp=u;u=stk[top--];stk[++top]=tmp;}
			ans[++cdt]=u;if(u==i)Ans=cdt;++t;for(int v:T[t])stk[++top]=v;T[t].clear();
			for(int v:G[u])if(!(--deg[v])){if(a[v]<=t)stk[++top]=v;else T[a[v]].push_back(v);}
		}
		if(i==1){drep(cdt,1,i)printf("%d ",ans[i]);puts("");} printf("%d ",n-Ans+1);
	}
	putchar('\n');return 0;
}
